   164→            var mrp = line.MRP > 0 ? line.MRP : InventoryService.CalculateMrp(line.PurchasePrice, margin);
   165→
   166→            if (line.Id > 0 && existingItemIds.Contains(line.Id))
   167→            {
   168→                // Existing item: adjust stock difference
   169→                var orig = existing.Items.First(i => i.Id == line.Id);
   170→                int diff = line.Quantity - orig.Quantity;
   171→                if (diff != 0)
   172→                {
   173→                    await inventoryService.AdjustStockAsync(new StockAdjustmentRequest
   174→                    {
