   190→                // New item
   191→                var newItem = new PurchaseItem
   192→                {
   193→                    MedicineId = medicine.Id,
   194→                    MedicineName = medicine.Name,
   195→                    Quantity = line.Quantity,
   196→                    PurchasePrice = line.PurchasePrice,
