    26→
    27→    public async Task<IActionResult> OnGetAsync(string? name)
    28→    {
    29→        if (string.IsNullOrWhiteSpace(name))
    30→            return RedirectToPage("/Purchase/Index");
    31→
    32→        SupplierName = name.Trim();
    33→
    34→        // Load purchases
    35→        Purchases = await purchaseService.GetBySupplierAsync(SupplierName);
    36→
    37→        // Load supplier profile if exists in Suppliers table
    38→        SupplierProfile = await db.Suppliers
    39→            .FirstOrDefaultAsync(s => s.Name == SupplierName && s.IsActive);
    40→
    41→        // Load payables for this supplier
    42→        Payables = await db.Payables
    43→            .Where(p => p.SupplierName.ToLower() == SupplierName.ToLower())
    44→            .OrderByDescending(p => p.DueDate)
    45→            .ToListAsync();
    46→
    47→        // Compute stats
    48→        TotalSpend = Purchases.Sum(p => p.TotalAmount);
    49→        AvgInvoice = Purchases.Count > 0 ? TotalSpend / Purchases.Count : 0;
    50→        TotalItems = Purchases.SelectMany(p => p.Items).Sum(i => i.Quantity);
    51→
    52→        var unpaidPayables = Payables.Where(p => p.Status != PayableStatus.Paid).ToList();
    53→        PendingPayable = unpaidPayables.Sum(p => p.PendingAmount);
    54→        OverdueCount = unpaidPayables.Count(p => p.IsOverdue);
    55→
    56→        // Top medicines by spend
    57→        TopMedicines = Purchases
    58→            .SelectMany(p => p.Items)
    59→            .GroupBy(i => i.MedicineName)
    60→            .Select(g => (Name: g.Key, Qty: g.Sum(i => i.Quantity), Spend: g.Sum(i => i.Amount)))
    61→            .OrderByDescending(x => x.Spend)
    62→            .Take(10)
    63→            .ToList();
    64→
    65→        return Page();
    66→    }
